/**
 * Residential production-rate reference records keyed by stable IDs.
 *
 * Activity master links via productionRateId — not by activityCode or csiCode alone.
 * Multiple records may share a csiCode; use productionRateId for unambiguous lookup.
 *
 * Values are bare man-hours per unit (labor-hours before crew-size multiplication).
 * Sources: RS Means Building Construction Cost Data (residential/light commercial).
 */

export interface ProductionRateReference {
  /** Stable lookup key (e.g. "03-31-00-footings-direct-chute"). Must be unique. */
  id: string;
  /** CSI MasterFormat section code (e.g. "03 31 00"). NOT unique across records. */
  csiCode: string;
  itemDescription: string;
  unit: string;
  defaultCrewSize: number;
  dailyOutput: number;
  dailyOutputUnit: string;
  /** Bare man-hours required per unit before crew size is applied. */
  bareManHoursPerUnit: number;
  /** Two-digit CSI division number matching the first two digits of csiCode. */
  sourceDivisionCode: string;
  notes?: string;
}

/** @deprecated Use ProductionRateReference instead. */
export type ResidentialProductionRate = ProductionRateReference;

